@@ -4,9 +4,19 @@
 // only when the text was actually shortened.
 function truncate(text, limit) {
   if (text.length <= limit) {
-    return text + "…";
+    return text;
   }
-  return text.slice(0, limit) + " …";
+
+  // Try to find the last space within the limit
+  const substring = text.slice(0, limit);
+  const lastSpaceIndex = substring.lastIndexOf(" ");
+
+  if (lastSpaceIndex !== -1) {
+    return substring.slice(0, lastSpaceIndex) + "…";
+  }
+
+  // If no space is found, the word is longer than the limit, so cut it
+  return substring + "…";
 }

 module.exports = { truncate };
